```typescript
async function retry<T>(
  fn: () => Promise<T>,
  opts: {
    maxRetries?: number;
    baseDelayMs?: number;
    maxDelayMs?: number;
    shouldRetry?: (error: unknown) => boolean;
  } = {},
): Promise<T> {
  const {
    maxRetries = 3,
    baseDelayMs = 1000,
    maxDelayMs = 30000,
    shouldRetry = () => true,
  } = opts;

  let lastError: unknown;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;

      if (attempt === maxRetries || !shouldRetry(err)) {
        throw err;
      }

      const delay = Math.min(
        baseDelayMs * 2 ** attempt + Math.random() * 1000, // jitter
        maxDelayMs,
      );

      await new Promise((r) => setTimeout(r, delay));
    }
  }

  throw lastError; // unreachable, but satisfies TypeScript
}
```

Usage:

```typescript
const data = await retry(() => fetch("https://api.example.com/data"), {
  maxRetries: 5,
  shouldRetry: (err) => {
    // Don't retry 4xx errors (client's fault)
    if (err instanceof Response && err.status >= 400 && err.status < 500) {
      return false;
    }
    return true;
  },
});
```

The jitter (`Math.random() * 1000`) prevents thundering herd when multiple clients retry simultaneously.

